
import { getHorizontalLabelPosition } from './get-horizontal-label-position.js';
import {
  calculateOptimalEllipsis,
  calculateOptimalPlacement,
} from './labels-collision.js';
import type { TruncationMode } from '../../../../../../typography/text-ellipsis/TextEllipsis.js';
import { charsFontWidth12pixelsSize500Map } from '../../../text-ellipsis/chars-font-width-map.js';
import { calculateWidth } from '../../../text-ellipsis/truncate-string.js';
import {
  HorizontalCoords,
  LabelAlignment,
  RangeLabel,
} from '../types/range-legend.internal.js';

/**
 * Check if for the given label position the text will fit in the bounds of the container.
 * In the case where it does not fit due to the start position, it determines
 * the optimal starting position of the label in order to have the label fully displayed.
 * In the case where the label does not fit due to the length applies the
 * ellipsis to it.
 */
export const handleCollisionInHorizontalLayout = (
  labelText: string,
  segment: HorizontalCoords,
  alignment: LabelAlignment,
  truncationMode: TruncationMode,
  bounds: number[],
): RangeLabel => {
  const labelWidth = calculateWidth(
    labelText,
    charsFontWidth12pixelsSize500Map,
  );
  const { x: labelX, y: labelY } = getHorizontalLabelPosition(
    labelWidth,
    segment.start,
    segment.end,
    alignment,
  );
  const isTruncationNeeded = bounds[0] + labelWidth > bounds[1];

  if (!isTruncationNeeded) {
    const candidateStartPos = labelX;
    const candidateEndPos = labelX + labelWidth;

    return {
      text: labelText,
      x: calculateOptimalPlacement(
        candidateStartPos,
        candidateEndPos,
        bounds[0],
        bounds[1],
      ),
      y: labelY,
    };
  } else {
    const { text, x } = calculateOptimalEllipsis(
      labelText,
      labelX,
      labelX + labelWidth,
      truncationMode,
      bounds[0],
      bounds[1],
    );

    return { text, x, y: labelY };
  }
};
